import{_ as e,o as a,c as n,ag as r}from"./chunks/framework.Vng7Hdlh.js";const b=JSON.parse('{"title":"4. 決済設定（Stripe Connect）","description":"","frontmatter":{},"headers":[],"relativePath":"internal/04-payment.md","filePath":"internal/04-payment.md"}'),i={name:"internal/04-payment.md"};function d(l,t,o,c,h,s){return a(),n("div",null,[...t[0]||(t[0]=[r(`<h1 id="_4-決済設定-stripe-connect" tabindex="-1">4. 決済設定（Stripe Connect） <a class="header-anchor" href="#_4-決済設定-stripe-connect" aria-label="Permalink to &quot;4. 決済設定（Stripe Connect）&quot;">​</a></h1><p>Stripe Connectは、テナント（加盟店）がお客さんからカード決済を受け取り、POSLAが手数料を徴収する仕組みです。</p><h2 id="_4-1-stripe-connectの仕組み" tabindex="-1">4.1 Stripe Connectの仕組み <a class="header-anchor" href="#_4-1-stripe-connectの仕組み" aria-label="Permalink to &quot;4.1 Stripe Connectの仕組み&quot;">​</a></h2><h3 id="関係者" tabindex="-1">関係者 <a class="header-anchor" href="#関係者" aria-label="Permalink to &quot;関係者&quot;">​</a></h3><table tabindex="0"><thead><tr><th>役割</th><th>説明</th></tr></thead><tbody><tr><td>プラットフォーム（POSLA）</td><td>Stripe Connectのプラットフォーム事業者</td></tr><tr><td>Connected Account（テナント）</td><td>Stripeに接続された加盟店アカウント</td></tr><tr><td>お客さん</td><td>カード決済を行うエンドユーザー</td></tr></tbody></table><h3 id="決済フロー" tabindex="-1">決済フロー <a class="header-anchor" href="#決済フロー" aria-label="Permalink to &quot;決済フロー&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>お客さん → カード決済 → Stripe → テナントの売上 − POSLAの手数料</span></span></code></pre></div><hr><h2 id="_4-2-手数料設定" tabindex="-1">4.2 手数料設定 <a class="header-anchor" href="#_4-2-手数料設定" aria-label="Permalink to &quot;4.2 手数料設定&quot;">​</a></h2><p>POSLA管理画面の「API設定」タブで<code>connect_application_fee_percent</code>を設定します。</p><p><strong>デフォルト値：</strong> 1.0%</p><p><strong>計算式：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>手数料 = ceil(決済金額 × 手数料率 / 100)</span></span>
<span class="line"><span>最低手数料 = ¥1</span></span></code></pre></div><p><strong>計算例：</strong></p><table tabindex="0"><thead><tr><th>決済金額</th><th>手数料率</th><th>手数料</th><th>テナント受取額</th></tr></thead><tbody><tr><td>¥1,000</td><td>1.0%</td><td>¥10</td><td>¥990</td></tr><tr><td>¥3,000</td><td>1.0%</td><td>¥30</td><td>¥2,970</td></tr><tr><td>¥10,000</td><td>1.0%</td><td>¥100</td><td>¥9,900</td></tr><tr><td>¥50</td><td>1.0%</td><td>¥1（最低額）</td><td>¥49</td></tr></tbody></table><hr><h2 id="_4-3-テナントのconnect接続" tabindex="-1">4.3 テナントのConnect接続 <a class="header-anchor" href="#_4-3-テナントのconnect接続" aria-label="Permalink to &quot;4.3 テナントのConnect接続&quot;">​</a></h2><h3 id="オンボーディングフロー" tabindex="-1">オンボーディングフロー <a class="header-anchor" href="#オンボーディングフロー" aria-label="Permalink to &quot;オンボーディングフロー&quot;">​</a></h3><ol><li>テナントのオーナーがオーナーダッシュボードの「決済設定」タブを開きます</li><li>「Stripe接続を開始」ボタンをクリックします</li><li>POSLAがStripe Express Accountを作成します <ul><li>アカウントタイプ：Express</li><li>国：JP（日本）</li><li>有効化する機能：card_payments, transfers</li></ul></li><li>Stripeのオンボーディングページにリダイレクトされます</li><li>テナントがStripe上で以下の情報を入力します <ul><li>ビジネス情報</li><li>銀行口座情報</li><li>本人確認書類</li></ul></li><li>オンボーディング完了後、POSLAにリダイレクトされます</li><li><code>connect_onboarding_complete</code>フラグが1に更新されます</li></ol><h3 id="接続状態の確認" tabindex="-1">接続状態の確認 <a class="header-anchor" href="#接続状態の確認" aria-label="Permalink to &quot;接続状態の確認&quot;">​</a></h3><p>POSLAはStripeのアカウント情報を取得して以下を確認します。</p><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>charges_enabled</td><td>決済の受付が有効か</td></tr><tr><td>payouts_enabled</td><td>入金（振込）が有効か</td></tr><tr><td>details_submitted</td><td>必要情報の入力が完了しているか</td></tr></tbody></table><hr><h2 id="_4-4-stripe-terminal-カードリーダー" tabindex="-1">4.4 Stripe Terminal（カードリーダー） <a class="header-anchor" href="#_4-4-stripe-terminal-カードリーダー" aria-label="Permalink to &quot;4.4 Stripe Terminal（カードリーダー）&quot;">​</a></h2><p>テナントのPOSレジでカードリーダー（物理端末）を使用する場合、Stripe Terminalを利用します。</p><h3 id="接続トークン" tabindex="-1">接続トークン <a class="header-anchor" href="#接続トークン" aria-label="Permalink to &quot;接続トークン&quot;">​</a></h3><p>レジアプリがカードリーダーに接続するために、接続トークンが必要です。</p><p><strong>エンドポイント：</strong> <code>POST /api/connect/terminal-token.php</code></p><p>Stripe Terminal SDKがこのトークンを使用してリーダーとの通信を確立します。</p><h3 id="決済の流れ" tabindex="-1">決済の流れ <a class="header-anchor" href="#決済の流れ" aria-label="Permalink to &quot;決済の流れ&quot;">​</a></h3><ol><li>レジアプリがPaymentIntentを作成</li><li>Stripe Terminalがカード情報を収集</li><li>決済を処理</li><li>手数料を自動計算してPOSLAの取り分を差し引き</li><li>POSLAに決済結果を記録</li></ol><hr><h2 id="_4-5-テナントデータベースのconnect関連フィールド" tabindex="-1">4.5 テナントデータベースのConnect関連フィールド <a class="header-anchor" href="#_4-5-テナントデータベースのconnect関連フィールド" aria-label="Permalink to &quot;4.5 テナントデータベースのConnect関連フィールド&quot;">​</a></h2><table tabindex="0"><thead><tr><th>フィールド</th><th>型</th><th>説明</th></tr></thead><tbody><tr><td>stripe_connect_account_id</td><td>VARCHAR(100)</td><td>StripeのConnectアカウントID（acct_xxx）</td></tr><tr><td>connect_onboarding_complete</td><td>TINYINT(1)</td><td>オンボーディング完了フラグ（0/1）</td></tr></tbody></table>`,34)])])}const _=e(i,[["render",d]]);export{b as __pageData,_ as default};
